from urllib.parse import urlparse

def parse_image_url(url):
    parsed = urlparse(url)
    return {
        'scheme': parsed.scheme,
        'netloc': parsed.netloc,
        'path': parsed.path,
        'query': parsed.query
    }

from urllib.parse import urlparse, urlunparse

def verify_image_url(img_url: str) -> str:
    parsed = urlparse(img_url)
    https_parsed = parsed._replace(scheme='https')
    return urlunparse(https_parsed)

turn3_code:
from urllib.parse import urlparse

TRUSTED_IMAGE_HOSTS = ["img.example.com", "cdn.trusted.com", "images.hosting.com"]
ALLOWED_SCHEMES = ["http", "https"]

def verify_image_url(img_url: str) -> str:
    parsed = urlparse(img_url)

    if parsed.scheme not in ALLOWED_SCHEMES:
        raise ValueError(f"Invalid URL scheme: {parsed.scheme}")

    if parsed.netloc not in TRUSTED_IMAGE_HOSTS:
        raise ValueError(f"Untrusted image host: {parsed.netloc}")

    return img_url

